-- ── SBN → CBHPM mappings ─────────────────────────────────────────────────────
INSERT INTO sbn_cbhpm_mappings (sbn_procedure_id, cbhpm_code_id, porte_code, sort_order)
SELECT sp.id, cc.id, '2B', 1
FROM   sbn_procedures sp, cbhpm_codes cc
WHERE  sp.code = '1' AND cc.code = '1.01.01.01-2'
ON CONFLICT (sbn_procedure_id, cbhpm_code_id) DO NOTHING;
INSERT INTO sbn_cbhpm_mappings (sbn_procedure_id, cbhpm_code_id, porte_code, sort_order)
SELECT sp.id, cc.id, '1C', 2
FROM   sbn_procedures sp, cbhpm_codes cc
WHERE  sp.code = '1' AND cc.code = '4.13.01.07-2'
ON CONFLICT (sbn_procedure_id, cbhpm_code_id) DO NOTHING;
INSERT INTO sbn_cbhpm_mappings (sbn_procedure_id, cbhpm_code_id, porte_code, sort_order)
SELECT sp.id, cc.id, '1B', 3
FROM   sbn_procedures sp, cbhpm_codes cc
WHERE  sp.code = '1' AND cc.code = '4.13.01.20-0'
ON CONFLICT (sbn_procedure_id, cbhpm_code_id) DO NOTHING;
